import{_ as t,o,c as a,ae as r}from"./chunks/framework.B6gjLfeO.js";const g=JSON.parse('{"title":"Home Page (New)","description":"","frontmatter":{"title":"Home Page (New)","slug":"home-page"},"headers":[],"relativePath":"account-hub/home-page.md","filePath":"account-hub/home-page.md"}'),s={name:"account-hub/home-page.md"};function i(n,e,l,h,u,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <a href="https://branchdocs.app.link/e/home-page-to-dashboard" target="_blank" rel="noreferrer">Home page</a> is your central hub for getting started with Branch. It&#39;s designed to guide you through the essential setup tasks, track your progress, and provide easy access to helpful resources.</p><p>This page gives you a high-level overview of your overall Branch implementation progress, and well as detailed steps to take that will help make sure you are getting the most out of the Branch Growth Platform.</p><div class="info custom-block"><p class="custom-block-title">Note</p><p>The Home page is available for self-serve customers with new accounts created after July 7, 2025. This page will continue to <strong>roll out to our remaining customers throughout 2025</strong>.</p></div><h2 id="home-page-features" tabindex="-1">Home page features <a class="header-anchor" href="#home-page-features" aria-label="Permalink to &quot;Home page features&quot;">​</a></h2><p>The Home page offers several features that make it easier to see where you are in the implementation process.</p><h3 id="branch-setup-checklist" tabindex="-1">Branch setup checklist <a class="header-anchor" href="#branch-setup-checklist" aria-label="Permalink to &quot;Branch setup checklist&quot;">​</a></h3><p>The <strong>Branch setup</strong> checklist outlines the setup tasks that need to be completed for a successful Branch implementation.</p><p>The tasks are grouped into logical categories like “Account setup”, “Link domain”, and more to guide you through the process smoothly.</p><p>Each task card gives you important information at a glance:</p><ul><li><p><strong>Title and description:</strong> Explains what the task is and why it&#39;s important.</p></li><li><p><strong>Time estimate</strong>: Shows the approximate time it takes to complete the task.</p></li><li><p><strong>Role tag</strong>:Indicates who on your team is typically responsible for this task (e.g., Admin, Developer).</p></li><li><p><strong>Status label</strong>: The current state of the task.</p><ul><li><strong>To Do</strong>: The default state for an incomplete task.</li><li><strong>Complete</strong>: The task has been finished. The card will be marked as &quot;Complete&quot; and may show the initial of the team member who completed it.</li><li><strong>Dismissed</strong>: You have chosen to hide this task from your main view.</li></ul></li></ul><h4 id="interactive-task-cards" tabindex="-1">Interactive task cards <a class="header-anchor" href="#interactive-task-cards" aria-label="Permalink to &quot;Interactive task cards&quot;">​</a></h4><p>The task cards are interactive, allowing you to take action directly from the Home page.</p><ul><li><p><strong>Action buttons:</strong> Each card has a primary call-to-action button (e.g., &quot;Invite team,&quot; &quot;Set timezone,&quot; &quot;Configure link domain&quot;) that will take you to the relevant page to complete the task.</p></li><li><p><strong>Dropdown menus:</strong> Some tasks, like &quot;Integrate the Branch SDK,&quot; have dropdown menus that provide more specific options and links to detailed guides (e.g., iOS, Android, or Web SDK guides).</p></li><li><p><strong>More Options Menu (</strong><code>...</code><strong>):</strong> Clicking the three-dot menu on a task card reveals additional actions:</p><ul><li><strong>Mark complete:</strong> Manually mark a task as finished.</li><li><strong>Dismiss:</strong> Hide the task from your to-do list.</li><li><strong>Mark as to do:</strong> Revert a &quot;Dismissed&quot; or &quot;Complete&quot; task back to the &quot;To do&quot; state.</li></ul></li></ul><h4 id="filters" tabindex="-1">Filters <a class="header-anchor" href="#filters" aria-label="Permalink to &quot;Filters&quot;">​</a></h4><p>You can also use the <strong>Role</strong> and <strong>Status</strong> dropdown filters to customize your view of the setup tasks, making it easier to see what&#39;s relevant to you or what&#39;s still pending.</p><h3 id="setup-progress-tracker" tabindex="-1">Setup progress tracker <a class="header-anchor" href="#setup-progress-tracker" aria-label="Permalink to &quot;Setup progress tracker&quot;">​</a></h3><p>Located on the right side of the page, the <strong>Setup progress</strong> module gives you a high-level overview of how much of the setup you&#39;ve completed.</p><p>The progress bar updates as you and your team complete the required tasks.</p><h3 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h3><p>Below the progress tracker, the <strong>Resources</strong> section provides links to valuable information to help you succeed with Branch. This includes:</p><ul><li><a href="https://help.branch.io/" target="_blank" rel="noreferrer"><strong>Help Center</strong></a><strong>:</strong> Find answers to common questions and detailed articles.</li><li><a href="https://www.branch.io/guides/" target="_blank" rel="noreferrer"><strong>Guides</strong></a><strong>:</strong> Access in-depth documentation and tutorials.</li><li><a href="https://www.branch.io/resources/category/blog/" target="_blank" rel="noreferrer"><strong>Blog</strong></a><strong>:</strong> Stay updated with the latest news and best practices.</li><li><a href="https://university.branch.io/pages/live-trainings" target="_blank" rel="noreferrer"><strong>Webinars</strong></a><strong>:</strong> Sign up for live training sessions led by an expert.</li><li><a href="https://university.branch.io/paths" target="_blank" rel="noreferrer"><strong>Branch University</strong></a><strong>:</strong> Enroll in courses to deepen your knowledge of the platform.</li></ul>',22)])])}const d=t(s,[["render",i]]);export{g as __pageData,d as default};
